insert into content_translations (entity_type, entity_id, field_name, language, translated_text, source_text_hash)
select 'MENU_ITEM', m.id, field_values.field_name, language_values.language, field_values.field_value, 'manual-menu-v10'
from dish_translations
join menu_items m on m.slug = dish_translations.slug
cross join lateral jsonb_each(dish_translations.translations) as language_values(language, data)
cross join lateral (values
    ('name', language_values.data ->> 'name'),
    ('description', language_values.data ->> 'description')
) as field_values(field_name, field_value)
on conflict (entity_type, entity_id, field_name, language)
do update set
    translated_text = excluded.translated_text,
    source_text_hash = excluded.source_text_hash,
    updated_at = now();
